mapper.select:
SELECT v.vehicle_name, pd.plan_detail_name, tc.tertiary_metric, tc.testcase_content, ts.id score_id, tc.id case_id, ts.score, ts.is_successful FROM test_state ts JOIN test_case tc ON ts.testcase_id = tc.id JOIN test_record tr ON ts.record_id = tr.id JOIN plan_detail pd on tc.function_id = pd.id JOIN vehicle v on v.id = tr.vehicle_id WHERE (ts.is_successful = 1 or ts.is_successful = 0) and tr.id in
#{vehicleId}
and pd.id < 8 and tc.tertiary_metric != "功能树检查" GROUP BY v.vehicle_name, pd.plan_detail_name, tc.tertiary_metric,tc.testcase_content,ts.id,ts.score,ts.is_successful ORDER BY v.vehicle_name, pd.plan_detail_name, tc.tertiary_metric,tc.testcase_content,ts.id,ts.score,ts.is_successful;

SELECT avgs.vehicle_name, avgs.function_id, avgs.plan_detail_name, avgs.tertiary_metric, avgs.count, avgs.avg_score, COALESCE(w.weight, 1.0) AS weight, -- 计算加权值：均分 × 权重 avgs.avg_score * COALESCE(w.weight, 1.0) AS weighted_score FROM ( -- 步骤1: 计算每个车辆、问题类型下各三级指标的均分 SELECT v.vehicle_name, tc.function_id, tc.tertiary_metric, COUNT(ts.id) count, pd.plan_detail_name, AVG(ts.score) AS avg_score FROM test_state ts JOIN test_case tc ON ts.testcase_id = tc.id JOIN test_record tr ON ts.record_id = tr.id JOIN plan_detail pd on tc.function_id = pd.id JOIN vehicle v on v.id = tr.vehicle_id WHERE (ts.is_successful = 1 or ts.is_successful = 0) -- 只统计成功的测试 and tr.id in
#{vehicleId}
and tc.tertiary_metric != "功能树检查" and tc.function_id < 7 and ts.score!=0 GROUP BY v.vehicle_name, tc.function_id, tc.tertiary_metric, pd.plan_detail_name ) AS avgs -- 关联权重表（严格按问题类型和三级指标匹配） LEFT JOIN tertiary_metric_weight w ON w.type = avgs.function_id -- 匹配问题类型 AND w.tertiary_metric = avgs.tertiary_metric -- 匹配三级指标

SELECT base.vehicle_name, base.plan_detail_name, -- 对相同问题类型ID下的所有加权值求和 SUM(base.weighted_score) AS 'function_domain_score' FROM ( -- 步骤2: 将均分乘以权重 SELECT avgs.vehicle_name, avgs.function_id, avgs.plan_detail_name, avgs.tertiary_metric, avgs.count, avgs.avg_score, COALESCE(w.weight, 1.0) AS weight, -- 计算加权值：均分 × 权重 avgs.avg_score * COALESCE(w.weight, 1.0) AS weighted_score FROM ( -- 步骤1: 计算每个车辆、问题类型下各三级指标的均分 SELECT v.vehicle_name, tc.function_id, tc.tertiary_metric, COUNT(ts.id) count, pd.plan_detail_name, AVG(ts.score) AS avg_score FROM test_state ts JOIN test_case tc ON ts.testcase_id = tc.id JOIN test_record tr ON ts.record_id = tr.id JOIN plan_detail pd on tc.function_id = pd.id JOIN vehicle v on v.id = tr.vehicle_id WHERE (ts.is_successful = 1 or ts.is_successful = 0) -- 只统计成功的测试 and tr.id in
#{vehicleId}
and tc.tertiary_metric != "功能树检查" and tc.function_id < 7 and ts.score!=0 GROUP BY v.vehicle_name, tc.function_id, tc.tertiary_metric, pd.plan_detail_name ) AS avgs -- 关联权重表（严格按问题类型和三级指标匹配） LEFT JOIN tertiary_metric_weight w ON w.type = avgs.function_id -- 匹配问题类型 AND w.tertiary_metric = avgs.tertiary_metric -- 匹配三级指标 ) AS base -- 步骤3: 对相同问题类型ID下的所有加权值求和 GROUP BY base.vehicle_name, base.function_id ORDER BY base.vehicle_name, base.function_id;
